// user.dart
import 'package:objectbox/objectbox.dart';

@Entity()
class User {
  @Id() int id = 0;                        // primary key (0 = auto-assign)

  @Unique()
  @Index()
  String email;

  String name;

  DateTime? createdAt;

  // Relations — bidirectional by design
  final orders = ToMany<Order>();          // 1:N
  final profile = ToOne<Profile>();        // 1:1

  User({required this.email, required this.name, this.createdAt});
}

@Entity()
class Order {
  @Id() int id = 0;

  @Index()
  int totalCents = 0;

  DateTime createdAt = DateTime.now();

  final owner = ToOne<User>();             // back-reference (auto by ObjectBox)
}

@Entity()
class Profile { /* ... */ }

// Run: dart run build_runner build --delete-conflicting-outputs

// ============ Open + use ============
import 'objectbox.g.dart';                  // generated by build_runner
import 'package:path_provider/path_provider.dart';
import 'package:path/path.dart' as p;

late final Store store;
late final Box<User> userBox;
late final Box<Order> orderBox;

Future<void> openObjectBox() async {
  final dir = await getApplicationDocumentsDirectory();
  store = await openStore(directory: p.join(dir.path, 'objectbox'));
  userBox  = store.box<User>();
  orderBox = store.box<Order>();
}

// Insert
final ada = User(email: 'ada@x.com', name: 'Ada Lovelace', createdAt: DateTime.now());
ada.id = userBox.put(ada);                   // put returns the assigned id

// Add a related order
final order = Order()..totalCents = 4299;
order.owner.target = ada;                    // ToOne
orderBox.put(order);
ada.orders.add(order);                       // ToMany
userBox.put(ada);

// Query — fluent DSL
final query = userBox.query(User_.email.equals('ada@x.com')).build();
final ada2 = query.findFirst();
query.close();

// Complex query
final recentBigSpenders = orderBox
    .query(Order_.totalCents.greaterThan(10000)
           .and(Order_.createdAt.greaterThan(DateTime(2026, 1, 1).millisecondsSinceEpoch)))
    .order(Order_.totalCents, flags: Order.descending)
    .build();
final top = recentBigSpenders.find();
recentBigSpenders.close();

// Reactive stream
final stream = userBox.query().watch(triggerImmediately: true);
stream.listen((q) {
  final users = q.find();
  print('now ${users.length} users');
});

